{action_set_definitions}: {
  "get_environment_state": {
    "description": "Retrieves the current state of the CI/CD pipeline, including workspace files, git commit hash, and overall status.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "pipeline_status": "FAILED",
      "workspace_files": [
        "deploy/canary.yaml",
        "deploy/production.yaml"
      ],
      "git_commit": "a1b2c3d"
    }
  },
  "query_service_telemetry": {
    "description": "Retrieves performance metrics (latency, error rate, throughput) for a specific service version to diagnose failures.",
    "parameters": {
      "type": "object",
      "properties": {
        "service_name": {
          "type": "string",
          "description": "Name of the service (e.g., 'fraud-detection')."
        },
        "version": {
          "type": "string",
          "description": "The version tag to query (e.g., 'v1.5')."
        }
      },
      "required": [
        "service_name",
        "version"
      ]
    },
    "example_output": {
      "error_rate": 0.15,
      "p99_latency_ms": 1200,
      "status": "unstable"
    }
  },
  "adjust_traffic_routing": {
    "description": "Modifies the traffic weight distribution between different versions of a service in the production environment.",
    "parameters": {
      "type": "object",
      "properties": {
        "service_name": {
          "type": "string"
        },
        "traffic_splits": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "version": {
                "type": "string"
              },
              "weight": {
                "type": "integer",
                "description": "Percentage of traffic (0-100)."
              }
            }
          }
        }
      },
      "required": [
        "service_name",
        "traffic_splits"
      ]
    },
    "example_output": {
      "status": "success",
      "current_routing": "v1.4: 100%, v1.5: 0%"
    }
  },
  "file_system_operation": {
    "description": "Reads from or writes to files in the local CI/CD workspace to modify deployment manifests.",
    "parameters": {
      "type": "object",
      "properties": {
        "operation": {
          "type": "string",
          "enum": [
            "read",
            "write"
          ]
        },
        "file_path": {
          "type": "string"
        },
        "content": {
          "type": "string",
          "description": "Required if operation is 'write'."
        }
      },
      "required": [
        "operation",
        "file_path"
      ]
    },
    "example_output": {
      "content": "apiVersion: apps/v1...",
      "status": "file_updated"
    }
  },
  "update_model_registry": {
    "description": "Updates the metadata and lifecycle status of a specific model version in the central registry.",
    "parameters": {
      "type": "object",
      "properties": {
        "model_id": {
          "type": "string"
        },
        "version": {
          "type": "string"
        },
        "status_update": {
          "type": "string",
          "enum": [
            "APPROVED",
            "BLACKLISTED",
            "DEPRECATED"
          ]
        }
      },
      "required": [
        "model_id",
        "version",
        "status_update"
      ]
    },
    "example_output": {
      "registry_sync": "synced",
      "new_status": "BLACKLISTED"
    }
  }
}
